import { LitElement, css, html, customElement, state, property } from '@umbraco-cms/backoffice/external/lit';
import { tagManagerRepository, type CmsTag, type PlainPair } from '../api/index.js';

@customElement('tag-edit-view')
export class TagEditViewElement extends LitElement {
	@property({ type: Number })
	tagId?: number;

	@state()
	private _tag: CmsTag | null = null;

	@state()
	private _loading = true;

	@state()
	private _saving = false;

	async connectedCallback() {
		super.connectedCallback();
		if (this.tagId) {
			await this._loadTag();
		}
	}

	private async _loadTag() {
		if (!this.tagId) return;

		this._loading = true;
		this._tag = await tagManagerRepository.getTagById(this.tagId);
		this._loading = false;
	}

	private async _save() {
		if (!this._tag) return;

		this._saving = true;
		const success = await tagManagerRepository.save(this._tag);
		this._saving = false;

		if (success) {
			// Show success notification
			this.dispatchEvent(
				new CustomEvent('notification', {
					bubbles: true,
					composed: true,
					detail: { headline: 'Success', message: 'Tag saved successfully', color: 'positive' },
				})
			);
		}
	}

	private async _delete() {
		if (!this._tag) return;

		const confirmed = confirm(`Are you sure you want to delete the tag "${this._tag.tag}"?`);
		if (!confirmed) return;

		this._saving = true;
		const success = await tagManagerRepository.deleteTag(this._tag);
		this._saving = false;

		if (success) {
			// Show success notification and navigate back
			this.dispatchEvent(
				new CustomEvent('notification', {
					bubbles: true,
					composed: true,
					detail: { headline: 'Success', message: 'Tag deleted successfully', color: 'positive' },
				})
			);
			history.back();
		}
	}

	private _onTagNameChange(e: Event) {
		if (!this._tag) return;
		const input = e.target as HTMLInputElement;
		this._tag = { ...this._tag, tag: input.value };
	}

	private _onMergeTagChange(e: Event) {
		if (!this._tag) return;
		const select = e.target as HTMLSelectElement;
		const selectedId = parseInt(select.value);
		const selectedTag = this._tag.tagsInGroup.options.find((t) => t.id === selectedId);
		if (selectedTag) {
			this._tag = {
				...this._tag,
				tagsInGroup: {
					...this._tag.tagsInGroup,
					selectedItem: selectedTag,
				},
			};
		}
	}

	render() {
		if (this._loading) {
			return html`<uui-loader></uui-loader>`;
		}

		if (!this._tag) {
			return html`<p>Tag not found</p>`;
		}

		return html`
			<uui-box>
				<div class="form-container">
					<uui-form-layout-item>
						<uui-label slot="label" for="tagName" required>Tag Name</uui-label>
						<uui-input
							id="tagName"
							.value=${this._tag.tag}
							@input=${this._onTagNameChange}
							?disabled=${this._saving}>
						</uui-input>
					</uui-form-layout-item>

					<uui-form-layout-item>
						<uui-label slot="label">Group</uui-label>
						<div>${this._tag.group}</div>
					</uui-form-layout-item>

					<uui-form-layout-item>
						<uui-label slot="label">Usage Count</uui-label>
						<div>${this._tag.noTaggedNodes} item(s)</div>
					</uui-form-layout-item>

					${this._tag.tagsInGroup && this._tag.tagsInGroup.options.length > 1
						? html`
								<uui-form-layout-item>
									<uui-label slot="label" for="mergeTag">Merge with Tag</uui-label>
									<uui-select
										id="mergeTag"
										.value=${this._tag.tagsInGroup.selectedItem.id.toString()}
										@change=${this._onMergeTagChange}
										?disabled=${this._saving}>
										${this._tag.tagsInGroup.options.map(
											(option) => html`
												<uui-select-option value="${option.id}">${option.tag}</uui-select-option>
											`
										)}
									</uui-select>
									<div slot="description">
										Select a tag to merge this tag into. All content using this tag will be
										reassigned.
									</div>
								</uui-form-layout-item>
						  `
						: ''}

					${this._tag.taggedDocuments && this._tag.taggedDocuments.length > 0
						? html`
								<uui-form-layout-item>
									<uui-label slot="label">Tagged Content</uui-label>
									<uui-ref-list>
										${this._tag.taggedDocuments.map(
											(doc) => html`
												<uui-ref-node
													name="${doc.documentName}"
													href="${doc.documentUrl}">
												</uui-ref-node>
											`
										)}
									</uui-ref-list>
								</uui-form-layout-item>
						  `
						: ''}

					${this._tag.taggedMedia && this._tag.taggedMedia.length > 0
						? html`
								<uui-form-layout-item>
									<uui-label slot="label">Tagged Media</uui-label>
									<uui-ref-list>
										${this._tag.taggedMedia.map(
											(media) => html`
												<uui-ref-node
													name="${media.documentName}"
													href="${media.documentUrl}">
												</uui-ref-node>
											`
										)}
									</uui-ref-list>
								</uui-form-layout-item>
						  `
						: ''}

					<div class="actions">
						<uui-button
							label="Save"
							look="primary"
							color="positive"
							@click=${this._save}
							?disabled=${this._saving}>
							${this._saving ? html`<uui-loader></uui-loader>` : 'Save'}
						</uui-button>
						<uui-button
							label="Delete"
							look="secondary"
							color="danger"
							@click=${this._delete}
							?disabled=${this._saving}>
							Delete
						</uui-button>
					</div>
				</div>
			</uui-box>
		`;
	}

	static styles = css`
		:host {
			display: block;
			padding: var(--uui-size-layout-1);
		}

		.form-container {
			display: flex;
			flex-direction: column;
			gap: var(--uui-size-space-5);
		}

		.actions {
			display: flex;
			gap: var(--uui-size-space-3);
			margin-top: var(--uui-size-space-5);
		}
	`;
}

declare global {
	interface HTMLElementTagNameMap {
		'tag-edit-view': TagEditViewElement;
	}
}

